document.addEventListener("DOMContentLoaded", () => {  "use strict";  const htmlElement = document.documentElement;  const themeToggleBtn = document.getElementById("theme-toggle");  const navbar = document.querySelector(".navbar");  const applyTheme = (theme) => {    htmlElement.setAttribute("data-bs-theme", theme);    localStorage.setItem("theme", theme);  };  const savedTheme = localStorage.getItem("theme");  if (savedTheme) {    applyTheme(savedTheme);  } else {    const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;    applyTheme(prefersDark ? "dark" : "light");  }  if (themeToggleBtn) {    themeToggleBtn.addEventListener("click", () => {      const nextTheme = htmlElement.getAttribute("data-bs-theme") === "dark" ? "light" : "dark";      applyTheme(nextTheme);    });  }  const syncNavbar = () => {    if (!navbar) return;    navbar.classList.toggle("scrolled", window.scrollY > 20);  };  syncNavbar();  window.addEventListener("scroll", syncNavbar, { passive: true });  document.querySelectorAll('a[href^="#"]:not([href="#"])').forEach((anchor) => {    anchor.addEventListener("click", (event) => {      const target = document.querySelector(anchor.getAttribute("href"));      if (!target) return;      event.preventDefault();      const offset = navbar ? navbar.offsetHeight + 12 : 0;      const top = target.getBoundingClientRect().top + window.scrollY - offset;      window.scrollTo({ top, behavior: "smooth" });    });  });  const revealItems = document.querySelectorAll("[data-reveal]");  if (revealItems.length) {    const revealObserver = new IntersectionObserver((entries, observer) => {      entries.forEach((entry) => {        if (!entry.isIntersecting) return;        entry.target.classList.add("is-visible");        observer.unobserve(entry.target);      });    }, {      threshold: 0.2,      rootMargin: "0px 0px -40px 0px"    });    revealItems.forEach((item) => revealObserver.observe(item));  }  const billingToggle = document.querySelector("[data-billing]");  if (billingToggle) {    const buttons = billingToggle.querySelectorAll("[data-plan]");    const amountNodes = document.querySelectorAll("[data-billing-amount]");    const labelNodes = document.querySelectorAll("[data-billing-label]");    const updateBilling = (mode) => {      buttons.forEach((button) => {        button.classList.toggle("is-active", button.dataset.plan === mode);      });      amountNodes.forEach((node) => {        node.textContent = node.dataset[mode];      });      labelNodes.forEach((node) => {        node.textContent = node.dataset[mode];      });    };    buttons.forEach((button) => {      button.addEventListener("click", () => updateBilling(button.dataset.plan));    });  }  document.querySelectorAll(".bento-card, .pricing-card, .testimonial-compact, .testimonial-featured, .doc-card").forEach((card) => {    card.addEventListener("pointermove", (event) => {      const rect = card.getBoundingClientRect();      card.style.setProperty("--spotlight-x", `${event.clientX - rect.left}px`);      card.style.setProperty("--spotlight-y", `${event.clientY - rect.top}px`);    });  });  const tiltStage = document.querySelector("[data-tilt]");  if (tiltStage && window.matchMedia("(pointer: fine)").matches) {    tiltStage.addEventListener("pointermove", (event) => {      const rect = tiltStage.getBoundingClientRect();      const x = (event.clientX - rect.left) / rect.width - 0.5;      const y = (event.clientY - rect.top) / rect.height - 0.5;      tiltStage.style.setProperty("--rotate-x", `${(y * -8).toFixed(2)}deg`);      tiltStage.style.setProperty("--rotate-y", `${(x * 10).toFixed(2)}deg`);    });    tiltStage.addEventListener("pointerleave", () => {      tiltStage.style.setProperty("--rotate-x", "0deg");      tiltStage.style.setProperty("--rotate-y", "0deg");    });  }  if (typeof AOS !== "undefined") {    AOS.init({      duration: 700,      easing: "ease-out-cubic",      once: true,      offset: 40,      disable: window.matchMedia("(prefers-reduced-motion: reduce)").matches    });  }});

// Anti-copy & Protect script
document.addEventListener('contextmenu', event => event.preventDefault());
document.addEventListener('keydown', event => {
    if (event.keyCode == 123) { // F12
        event.preventDefault();
        return false;
    }
    if (event.ctrlKey && event.shiftKey && event.keyCode == 73) { // Ctrl+Shift+I
        event.preventDefault();
        return false;
    }
    if (event.ctrlKey && event.shiftKey && event.keyCode == 74) { // Ctrl+Shift+J
        event.preventDefault();
        return false;
    }
    if (event.ctrlKey && event.keyCode == 85) { // Ctrl+U
        event.preventDefault();
        return false;
    }
    if (event.ctrlKey && event.keyCode == 83) { // Ctrl+S
        event.preventDefault();
        return false;
    }
});
document.addEventListener('selectstart', event => event.preventDefault());
